// Example: what happens when this is compiled and executed?
#include <stdio.h>
int vector[100];                // Global variable → global segment

bool IsNumberOdd(int n) {       // Parameter n → stack
  return ((n % 2) == 0);        // Note: this actually checks EVEN, not odd!
}

void main(void) {
  int poz, i;                   // Local variables → stack (uninitialized!)
  for (poz = 0, i = 1; poz < 100; i++) {
    if (IsNumberOdd(i)) {
      vector[poz++] = i;        // Writes to global memory
    }
  }
  printf("Found 100 odd numbers !");  // String literal → constants segment
}

