// Default alignment: sizeof = 12
struct Test {
    char x;    // offset 0
    // 1 byte padding
    short y;   // offset 2-3
    int z;     // offset 4-7
    char t;    // offset 8
    // 3 bytes padding (struct rounds to multiple of int=4)
};  // Total: 12

// #pragma pack(1): sizeof = 8, NO padding at all
#pragma pack(1)
struct Test {
    char x;    // offset 0
    short y;   // offset 1-2
    int z;     // offset 3-6
    char t;    // offset 7
};  // Total: 8

// #pragma pack(1) + __declspec(align(16)): sizeof = 16
#pragma pack(1)
__declspec(align(16)) struct Test {
    char x; short y; int z; char t;
};  // Packed to 8, but padded to align boundary of 16

