// C++ approach — class with encapsulation
class Person {
private:
    int Age;                     // Only accessible from within the class
public:
    void SetAge(int value);      // Public interface
    Person();                    // Constructor — auto-called at creation
};

void Person::SetAge(int value) {
    if ((value > 0) && (value < 200))   // Validation!
        this->Age = value;              // 'this' pointer — no manual passing
}

Person::Person() {
    this->Age = 10;              // Auto-initialization!
}

void main() {
    Person p;                    // Constructor called automatically!
    p.SetAge(10);                // Validated setter
    // p.Age = -1;               // COMPILER ERROR — Age is private!
}

class Person {
private:
    int Age, Height;
    static int X;           // Private static member
public:
    const char *Name;
    static int Y;           // Public static member
};

// Static members MUST be defined outside the class:
int Person::X;
int Person::Y = 10;

void main() {
    Person p;
    p.Y = 5;               // Access via instance
    Person::Y++;            // Access via class name — Y becomes 6
    // p.X = 6;             // ERROR: X is private
}

